import { api } from 'lwc';
import LightningOverlay from 'lightning/overlay';
export default class EditOverlay extends LightningOverlay {
    @api
    initialValue = '';
    handleInputChange(event) {
        this._value = event.target.value;
    }
    handleSave() {
        this.close(this._value || this.initialValue);
    }
    handleCancel() {
        this.close(null);
    }
    get editedValue() {
        return this._value !== undefined ? this._value : this.initialValue;
    }
}
